     1→import React, { Suspense, lazy, useState, useEffect, useCallback } from 'react';
     2→import { Sidebar } from './Sidebar';
     3→import { Footer as SaveStatusFooter } from './Footer';
     4→import { ErrorToastContainer } from './ErrorToast';
     5→import { SupportModal } from './SupportModal';
     6→import { AboutModal } from './AboutModal';
     7→import { PrivacyModal } from './PrivacyModal';
     8→import { OnboardingModal } from './OnboardingModal';
     9→import { CommandPalette } from './CommandPalette';
    10→import { useSidebarStore } from '../stores/useSidebarStore';
    11→import { useTerminalStore } from '../stores/useTerminalStore';
    12→
    13→// Lazy load AITerminal to avoid loading 900KB+ of AI provider SDKs in the main bundle
    14→const AITerminal = lazy(() => import('./AITerminal').then(m => ({ default: m.AITerminal })));
    15→
    16→/**
    17→ * Layout Component with Sidebar Navigation
    18→ */
    19→interface LayoutProps {
    20→  children: React.ReactNode;
    21→}
    22→
    23→export const Layout: React.FC<LayoutProps> = ({ children }) => {
    24→  const { isCollapsed, toggleMobileMenu } = useSidebarStore();
    25→  const { isOpen: isTerminalOpen, toggleTerminal } = useTerminalStore();
    26→  const [showSupportModal, setShowSupportModal] = useState(false);
    27→  const [supportModalTab, setSupportModalTab] = useState<'report' | 'help' | 'docs'>('report');
    28→  const [showCommandPalette, setShowCommandPalette] = useState(false);
    29→  const [showAboutModal, setShowAboutModal] = useState(false);
    30→  const [showPrivacyModal, setShowPrivacyModal] = useState(false);
    31→  const [showOnboardingModal, setShowOnboardingModal] = useState(false);
    32→
    33→  // Handler for opening support modal from command palette
    34→  const handleOpenSupportModal = (tab: 'report' | 'help' | 'docs') => {
    35→    setSupportModalTab(tab);
    36→    setShowSupportModal(true);
    37→    setShowCommandPalette(false);
    38→  };
    39→
    40→  // Handler for opening various modals from command palette
    41→  const handleOpenModal = useCallback((modalId: string) => {
    42→    setShowCommandPalette(false);
    43→    switch (modalId) {
    44→      case 'about':
    45→        setShowAboutModal(true);
    46→        break;
    47→      case 'privacy':
    48→        setShowPrivacyModal(true);
    49→        break;
    50→      case 'onboarding':
    51→        setShowOnboardingModal(true);
    52→        break;
    53→      case 'support':
    54→        setShowSupportModal(true);
    55→        break;
    56→      default:
    57→        break;
    58→    }
    59→  }, []);
    60→
    61→  // Global keyboard shortcuts
    62→  // Using capture phase to intercept before browser handles F1 and Cmd+K
    63→  useEffect(() => {
    64→    const handleKeyDown = (e: KeyboardEvent) => {
    65→      // Cmd+K (Mac) or Ctrl+K (Windows/Linux) - open command palette
    66→      if (e.key === 'k' && (e.metaKey || e.ctrlKey)) {
    67→        e.preventDefault();
    68→        e.stopPropagation();
    69→        setShowCommandPalette(true);
    70→        return;
    71→      }
    72→
    73→      // F1 key - open help modal
    74→      if (e.key === 'F1') {
    75→        e.preventDefault();
    76→        e.stopPropagation();
    77→        setShowSupportModal(true);
    78→        return;
    79→      }
    80→
    81→      // Ctrl+/ (Windows/Linux) or Cmd+/ (Mac) - open help modal
    82→      if (e.key === '/' && (e.metaKey || e.ctrlKey)) {
    83→        e.preventDefault();
    84→        e.stopPropagation();
    85→        setShowSupportModal(true);
    86→        return;
    87→      }
    88→    };
    89→
    90→    // Use capture: true to intercept events before they reach the browser
    91→    window.addEventListener('keydown', handleKeyDown, { capture: true });
    92→    return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
    93→  }, []);
    94→
    95→  return (
    96→    <div className="app h-screen bg-surface-light dark:bg-surface-dark flex overflow-hidden">
    97→      {/* Skip to main content link - visible on focus for keyboard users */}
    98→      <a
    99→        href="#main-content"
   100→        className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-1/2 focus:-translate-x-1/2 focus:z-[100] focus:px-4 focus:py-2 focus:bg-accent-blue focus:text-white focus:rounded-button focus:shadow-lg"
   101→      >
   102→        Skip to main content
   103→      </a>
   104→
   105→      {/* Mobile hamburger button */}
   106→      <button
   107→        onClick={toggleMobileMenu}
   108→        className="lg:hidden fixed top-4 left-4 z-50 p-2 rounded-button bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark shadow-lg transition-all duration-standard ease-smooth"
   109→        aria-label="Toggle navigation menu"
   110→      >
   111→        <span className="text-xl" aria-hidden="true">☰</span>
   112→      </button>
   113→
   114→      <Sidebar />
   115→
   116→      {/* Main content area with margin for sidebar */}
   117→      <div className="flex-1 flex flex-col transition-all duration-200 overflow-x-hidden overflow-y-hidden">
   118→        <main
   119→          id="main-content"
   120→          role="main"
   121→          tabIndex={-1}
   122→          className={`
   123→            flex-1 py-6 overflow-y-auto
   124→            transition-[margin] duration-200
   125→            focus:outline-none
   126→            ${/* Mobile: no margin (sidebars are overlays) */ ''}
   127→            ml-0 mr-0
   128→            ${/* Desktop: left margin for navigation sidebar */ ''}
   129→            ${isCollapsed ? 'lg:ml-[60px]' : 'lg:ml-[210px]'}
   130→            ${/* Desktop: right margin for AI terminal */ ''}
   131→            ${isTerminalOpen ? 'lg:mr-[375px]' : 'lg:mr-0'}
   132→          `}
   133→        >
   134→          <div className="w-full px-6">
   135→            {children}
   136→          </div>
   137→        </main>
   138→      </div>
   139→
   140→      {/* Save Status Footer (floating pill at bottom-center) */}
   141→      <SaveStatusFooter />
   142→
   143→      {/* AI Terminal Toggle Button (floating action button - top-right when closed) */}
   144→      {!isTerminalOpen && (
   145→        <button
   146→          onClick={toggleTerminal}
   147→          className="fixed top-4 right-4 mr-2 mt-2 w-10 h-10 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta text-white shadow-lg hover:shadow-xl transition-all z-40 flex items-center justify-center"
   148→          title="AI Terminal"
   149→          aria-label="Toggle AI Terminal"
   150→        >
   151→          🤖
   152→        </button>
   153→      )}
   154→
   155→      {/* AI Terminal Component (lazy loaded) */}
   156→      <Suspense fallback={null}>
   157→        <AITerminal />
   158→      </Suspense>
   159→
   160→      {/* Error Toast Notifications */}
   161→      <ErrorToastContainer />
   162→
   163→      {/* Global Support Modal (F1 or Cmd+Ctrl+/) */}
   164→      <SupportModal
   165→        isOpen={showSupportModal}
   166→        onClose={() => setShowSupportModal(false)}
   167→        initialTab={supportModalTab}
   168→      />
   169→
   170→      {/* About Modal (conditionally rendered) */}
   171→      {showAboutModal && (
   172→        <AboutModal onClose={() => setShowAboutModal(false)} />
   173→      )}
   174→
   175→      {/* Privacy Modal (conditionally rendered) */}
   176→      {showPrivacyModal && (
   177→        <PrivacyModal onClose={() => setShowPrivacyModal(false)} />
   178→      )}
   179→
   180→      {/* Onboarding Modal */}
   181→      <OnboardingModal
   182→        isOpen={showOnboardingModal}
   183→        onClose={() => setShowOnboardingModal(false)}
   184→      />
   185→
   186→      {/* Synapse - Neural Search (Cmd+K / Ctrl+K) */}
   187→      <CommandPalette
   188→        isOpen={showCommandPalette}
   189→        onClose={() => setShowCommandPalette(false)}
   190→        onOpenSupportModal={handleOpenSupportModal}
   191→        onOpenModal={handleOpenModal}
   192→      />
   193→    </div>
