import React, { Suspense, lazy, useState, useEffect, useCallback } from 'react';
import { Sidebar } from './Sidebar';
import { Footer as SaveStatusFooter } from './Footer';
import { ErrorToastContainer } from './ErrorToast';
import { SupportModal } from './SupportModal';
import { AboutModal } from './AboutModal';
import { PrivacyModal } from './PrivacyModal';
import { OnboardingModal } from './OnboardingModal';
import { CommandPalette } from './CommandPalette';
import { useSidebarStore } from '../stores/useSidebarStore';
import { useTerminalStore } from '../stores/useTerminalStore';

// Lazy load AITerminal to avoid loading 900KB+ of AI provider SDKs in the main bundle
const AITerminal = lazy(() => import('./AITerminal').then(m => ({ default: m.AITerminal })));

/**
 * Layout Component with Sidebar Navigation
 */
interface LayoutProps {
  children: React.ReactNode;
}

export const Layout: React.FC<LayoutProps> = ({ children }) => {
  const { isCollapsed, toggleMobileMenu } = useSidebarStore();
  const { isOpen: isTerminalOpen, toggleTerminal } = useTerminalStore();
  const [showSupportModal, setShowSupportModal] = useState(false);
  const [supportModalTab, setSupportModalTab] = useState<'report' | 'help' | 'docs'>('report');
  const [showCommandPalette, setShowCommandPalette] = useState(false);
  const [showAboutModal, setShowAboutModal] = useState(false);
  const [showPrivacyModal, setShowPrivacyModal] = useState(false);
  const [showOnboardingModal, setShowOnboardingModal] = useState(false);

  // Handler for opening support modal from command palette
  const handleOpenSupportModal = (tab: 'report' | 'help' | 'docs') => {
    setSupportModalTab(tab);
    setShowSupportModal(true);
    setShowCommandPalette(false);
  };

  // Handler for opening various modals from command palette
  const handleOpenModal = useCallback((modalId: string) => {
    setShowCommandPalette(false);
    switch (modalId) {
      case 'about':
        setShowAboutModal(true);
        break;
      case 'privacy':
        setShowPrivacyModal(true);
        break;
      case 'onboarding':
        setShowOnboardingModal(true);
        break;
      case 'support':
        setShowSupportModal(true);
        break;
      default:
        break;
    }
  }, []);

  // Global keyboard shortcuts
  // Using capture phase to intercept before browser handles F1 and Cmd+K
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Cmd+K (Mac) or Ctrl+K (Windows/Linux) - open command palette
      if (e.key === 'k' && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        e.stopPropagation();
        setShowCommandPalette(true);
        return;
      }

      // F1 key - open help modal
      if (e.key === 'F1') {
        e.preventDefault();
        e.stopPropagation();
        setShowSupportModal(true);
        return;
      }

      // Ctrl+/ (Windows/Linux) or Cmd+/ (Mac) - open help modal
      if (e.key === '/' && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        e.stopPropagation();
        setShowSupportModal(true);
        return;
      }
    };

    // Use capture: true to intercept events before they reach the browser
    window.addEventListener('keydown', handleKeyDown, { capture: true });
    return () => window.removeEventListener('keydown', handleKeyDown, { capture: true });
  }, []);

  return (
    <div className="app h-screen bg-surface-light dark:bg-surface-dark flex overflow-hidden">
      {/* Skip to main content link - visible on focus for keyboard users */}
      <a
        href="#main-content"
        className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-1/2 focus:-translate-x-1/2 focus:z-[100] focus:px-4 focus:py-2 focus:bg-accent-blue focus:text-white focus:rounded-button focus:shadow-lg"
      >
        Skip to main content
      </a>

      {/* Mobile hamburger button */}
      <button
        onClick={toggleMobileMenu}
        className="lg:hidden fixed top-4 left-4 z-50 p-2 rounded-button bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark shadow-lg transition-all duration-standard ease-smooth"
        aria-label="Toggle navigation menu"
      >
        <span className="text-xl" aria-hidden="true">☰</span>
      </button>

      <Sidebar />

      {/* Main content area with margin for sidebar */}
      <div className="flex-1 flex flex-col transition-all duration-200 overflow-x-hidden overflow-y-hidden">
        <main
          id="main-content"
          role="main"
          tabIndex={-1}
          className={`
            flex-1 py-6 overflow-y-auto
            transition-[margin] duration-200
            focus:outline-none
            ${/* Mobile: no margin (sidebars are overlays) */ ''}
            ml-0 mr-0
            ${/* Desktop: left margin for navigation sidebar */ ''}
            ${isCollapsed ? 'lg:ml-[60px]' : 'lg:ml-[210px]'}
            ${/* Desktop: right margin for AI terminal */ ''}
            ${isTerminalOpen ? 'lg:mr-[375px]' : 'lg:mr-0'}
          `}
        >
          <div className="w-full px-6">
            {children}
          </div>
        </main>
      </div>

      {/* Save Status Footer (floating pill at bottom-center) */}
      <SaveStatusFooter />

      {/* AI Terminal Toggle Button (floating action button - top-right when closed) */}
      {!isTerminalOpen && (
        <button
          onClick={toggleTerminal}
          className="fixed top-4 right-4 mr-2 mt-2 w-10 h-10 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta text-white shadow-lg hover:shadow-xl transition-all z-40 flex items-center justify-center"
          title="AI Terminal"
          aria-label="Toggle AI Terminal"
        >
          🤖
        </button>
      )}

      {/* AI Terminal Component (lazy loaded) */}
      <Suspense fallback={null}>
        <AITerminal />
      </Suspense>

      {/* Error Toast Notifications */}
      <ErrorToastContainer />

      {/* Global Support Modal (F1 or Cmd+Ctrl+/) */}
      <SupportModal
        isOpen={showSupportModal}
        onClose={() => setShowSupportModal(false)}
        initialTab={supportModalTab}
      />

      {/* About Modal (conditionally rendered) */}
      {showAboutModal && (
        <AboutModal onClose={() => setShowAboutModal(false)} />
      )}

      {/* Privacy Modal (conditionally rendered) */}
      {showPrivacyModal && (
        <PrivacyModal onClose={() => setShowPrivacyModal(false)} />
      )}

      {/* Onboarding Modal */}
      <OnboardingModal
        isOpen={showOnboardingModal}
        onClose={() => setShowOnboardingModal(false)}
      />

      {/* Synapse - Neural Search (Cmd+K / Ctrl+K) */}
      <CommandPalette
        isOpen={showCommandPalette}
        onClose={() => setShowCommandPalette(false)}
        onOpenSupportModal={handleOpenSupportModal}
        onOpenModal={handleOpenModal}
      />
    </div>
  );
};

