/**
 * Link Library Store
 *
 * Manages links (bookmarks) with:
 * - Import/Export (Netscape HTML format)
 * - Collections for organization
 * - AI-powered categorization
 * - Favorites and archive features
 *
 * Persists to IndexedDB via createSyncedStorage.
 */

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { createSyncedStorage } from '../lib/syncedStorage';

// ============================================================================
// Types
// ============================================================================

export interface Link {
  id: string;
  url: string;
  title: string;
  description?: string;
  favicon?: string;
  category?: string; // AI-suggested or manual
  tags: string[];
  isFavorite: boolean;
  isArchived: boolean;
  lastVisited?: Date;
  visitCount: number;
  createdAt: Date;
  updatedAt: Date;
}

export interface LinkCollection {
  id: string;
  name: string;
  icon?: string; // Emoji or custom
  color?: string; // Accent color
  linkIds: string[]; // Ordered list of link IDs
  isExpanded: boolean;
  sortOrder: number;
  createdAt: Date;
  updatedAt: Date;
}

export type ViewMode = 'grid' | 'list';
export type SortField = 'title' | 'createdAt' | 'updatedAt' | 'visitCount';
export type SortDirection = 'asc' | 'desc';

interface LinkLibraryState {
  // Data
  links: Record<string, Link>;
  collections: Record<string, LinkCollection>;

  // UI State (not persisted)
  viewMode: ViewMode;
  sortField: SortField;

