   295→    }
   296→
   297→    // Auto-save on blur (normal case or no shifts needed)
   298→    onSave(task.id, { [field]: value });
   299→  };
   300→
   301→  const handleAddTag = () => {
   302→    if (newTag.trim() && !tags.includes(newTag.trim())) {
   303→      const updatedTags = [...tags, newTag.trim()];
   304→      setTags(updatedTags);
   305→      onSave(task.id, { tags: updatedTags });
   306→      setNewTag('');
   307→    }
   308→  };
   309→
   310→  const handleRemoveTag = (tagToRemove: string) => {
   311→    const updatedTags = tags.filter(tag => tag !== tagToRemove);
   312→    setTags(updatedTags);
   313→    onSave(task.id, { tags: updatedTags });
   314→  };
   315→
   316→  // Dependency handlers
   317→  const handleAddDependency = (dependency: TaskDependency) => {
   318→    if (!task) return;
   319→    addDependency(task.id, dependency);
   320→  };
   321→
   322→  const handleRemoveDependency = (dependencyId: string) => {
   323→    if (!task) return;
   324→    removeDependency(task.id, dependencyId);
   325→  };
   326→
   327→  // Get dependency label for display
   328→  const getDependencyLabel = (type: DependencyType): string => {
   329→    const labels = {
   330→      'finish-to-start': 'FS',
   331→      'start-to-start': 'SS',
   332→      'finish-to-finish': 'FF',
   333→      'start-to-finish': 'SF',
   334→    };
   335→    return labels[type];
   336→  };
   337→
   338→  const getDependencyIcon = (type: DependencyType): string => {
   339→    const icons = {
