   405→
   406→  const availableTasks = tasks.filter(t => t.id !== task?.id);
   407→
   408→  return (
   409→    <>
   410→    <Modal isOpen={isOpen} onClose={onClose} title={task.title} maxWidth="2xl">
   411→      <div className="flex flex-col md:flex-row gap-3 pr-1">
   412→        {/* Left Side: Task Metadata (60%) */}
   413→        <div className="w-full md:w-3/5 space-y-2">
   414→          {/* Title */}
   415→          <div>
   416→            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   417→              Title
   418→            </label>
   419→            <input
