   422→              onChange={(e) => setTitle(e.target.value)}
   423→              onBlur={() => handleFieldBlur('title', title)}
   424→              className="w-full text-base font-semibold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue rounded px-1 py-0.5"
   425→              autoFocus
   426→            />
   427→          </div>
   428→
   429→          {/* Description */}
   430→          <div>
   431→            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   432→              Description
   433→            </label>
   434→            <textarea
   435→              value={description}
   436→              onChange={(e) => setDescription(e.target.value)}
